class Solution {
public:
    int longestDecomposition(string text) {
        int left = 0, right = text.size() - 1;
        int res = 0;
        while (left <= right) {
            bool found = false;
            int max_l = (right - left + 1) / 2;
            for (int l = 1; l <= max_l; ++l) {
                bool match = true;
                for (int i = 0; i < l; ++i) {
                    int left_idx = left + i;
                    int right_idx = right - l + 1 + i;
                    if (text[left_idx] != text[right_idx]) {
                        match = false;
                        break;
                    }
                }
                if (match) {
                    res += 2;
                    left += l;
                    right -= l;
                    found = true;
                    break;
                }
            }
            if (!found) {
                ++res;
                break;
            }
        }
        return res;
    }
};

